// Extract signal fields from the email body.
// Customize the parsing logic for each newsletter source:
//   - Unusual Whales: look for ticker + call/put sweep language
//   - Dividendology: look for ex-dividend dates
//   - Pure Power Picks: look for BUY/SELL + ticker in subject
//   - MarketWatch: look for analyst upgrade/downgrade language
//   - Simply Wall St.: look for overvalued/undervalued language

const email = $input.item.json;
const subject = email.subject || '';
const body = email.textPlain || email.textHtml || '';
const from = email.from?.value?.[0]?.address || '';

// Determine source from sender domain
let source = 'unknown';
if (from.includes('unusualwhales')) source = 'unusual_whales';
else if (from.includes('marketwatch') || from.includes('wsj.com')) source = 'marketwatch';
else if (from.includes('dividendology')) source = 'dividendology';
else if (from.includes('purpowerpicks') || from.includes('pure-power')) source = 'pure_power_picks';
else if (from.includes('simplywallst')) source = 'simply_wall_st';

// --- Ticker extraction ---
// Match $TICKER or standalone uppercase 1-5 letter word in subject
const tickerMatch = subject.match(/\$([A-Z]{1,5})/) || subject.match(/\b([A-Z]{1,5})\b/);
const symbol = tickerMatch ? tickerMatch[1] : null;

if (!symbol) {
  // Skip emails with no detectable ticker
  return [];
}

// --- Direction extraction ---
const lowerBody = (subject + ' ' + body).toLowerCase();
let direction = 'watchlist';
if (/\b(buy|bullish|long|call sweep|upgrade|undervalued|accumulate)\b/.test(lowerBody)) {
  direction = 'buy';
} else if (/\b(sell|bearish|short|put sweep|downgrade|overvalued|reduce)\b/.test(lowerBody)) {
  direction = 'sell';
} else if (/\b(hold|neutral|maintain)\b/.test(lowerBody)) {
  direction = 'hold';
}

// --- Tags ---
const tags = [];
if (/call sweep|unusual option/i.test(body)) tags.push('unusual_options', 'call_sweep');
if (/put sweep/i.test(body)) tags.push('unusual_options', 'put_sweep');
if (/dark pool/i.test(body)) tags.push('dark_pool');
if (/dividend|ex-div/i.test(body)) tags.push('dividend', 'income');
if (/upgrade/i.test(body)) tags.push('analyst', 'upgrade');
if (/downgrade/i.test(body)) tags.push('analyst', 'downgrade');
if (/momentum|swing/i.test(body)) tags.push('momentum', 'swing');
if (/fair value|valuation/i.test(body)) tags.push('fundamental', 'fair_value');

// --- Valid window ---
const now = new Date();
const validFrom = now.toISOString();
const validUntil = new Date(now.getTime() + 5 * 24 * 60 * 60 * 1000).toISOString(); // 5-day default

return [{
  json: {
    source,
    symbol,
    direction,
    conviction: 0.5, // default; override per-source if extractable
    valid_from: validFrom,
    valid_until: validUntil,
    headline: subject.slice(0, 255),
    raw_url: '',
    tags,
  }
}];
